     1→function isDateLike(value) {
     2→  if (value instanceof Date) return Number.isFinite(value.getTime());
     3→  if (typeof value !== 'string') return false;
     4→  const parsed = Date.parse(value);
     5→  return Number.isFinite(parsed);
     6→}
     7→
     8→export function toFiniteNumber(value) {
     9→  if (typeof value === 'number') return Number.isFinite(value) ? value : null;
    10→  if (typeof value === 'string') {
    11→    const parsed = Number(value.replace(/,/g, ''));
    12→    return Number.isFinite(parsed) ? parsed : null;
    13→  }
    14→  const parsed = Number(value);
    15→  return Number.isFinite(parsed) ? parsed : null;
    16→}
    17→
    18→function normalizeXYTrace(trace) {
    19→  const sourceY = Array.isArray(trace?.y) ? trace.y : [];
    20→  const sourceX = Array.isArray(trace?.x) ? trace.x : [];
    21→
    22→  if (!sourceY.length) return null;
    23→
    24→  const points = [];
    25→  for (let idx = 0; idx < sourceY.length; idx += 1) {
    26→    const y = toFiniteNumber(sourceY[idx]);
    27→    if (y === null) continue;
    28→    points.push({
    29→      x: sourceX[idx] ?? `${idx + 1}`,
    30→      y,
    31→    });
    32→  }
    33→
    34→  if (!points.length) return null;
    35→
    36→  const shouldSortByDate =
    37→    trace?.type === 'scatter' &&
    38→    typeof trace?.mode === 'string' &&
    39→    trace.mode.includes('line') &&
    40→    points.every((point) => isDateLike(point.x));
    41→
    42→  if (shouldSortByDate) {
    43→    points.sort((a, b) => Date.parse(a.x) - Date.parse(b.x));
    44→  }
    45→
    46→  return {
    47→    ...trace,
    48→    x: points.map((point) => point.x),
    49→    y: points.map((point) => point.y),
    50→  };
    51→}
    52→
    53→function normalizePieTrace(trace) {
    54→  const values = Array.isArray(trace?.values) ? trace.values : [];
    55→  const labels = Array.isArray(trace?.labels) ? trace.labels : [];
    56→
    57→  const points = [];
    58→  for (let idx = 0; idx < values.length; idx += 1) {
    59→    const value = toFiniteNumber(values[idx]);
    60→    if (value === null) continue;
    61→    points.push({
    62→      label: labels[idx] ?? `${idx + 1}`,
    63→      value,
    64→    });
    65→  }
    66→
    67→  if (!points.length) return null;
    68→
    69→  return {
    70→    ...trace,
    71→    labels: points.map((point) => point.label),
    72→    values: points.map((point) => point.value),
    73→  };
    74→}
    75→
    76→function normalizeSingleTrace(trace) {
    77→  if (!trace || typeof trace !== 'object') return null;
    78→  if (trace.type === 'pie') return normalizePieTrace(trace);
    79→  return normalizeXYTrace(trace);
    80→}
    81→
    82→export function normalizeTraces(data, { fallbackTraces = [] } = {}) {
    83→  const source = Array.isArray(data) ? data : [];
    84→  const normalized = source.map(normalizeSingleTrace).filter(Boolean);
    85→  if (normalized.length > 0) return normalized;
    86→
    87→  const fallback = Array.isArray(fallbackTraces) ? fallbackTraces : [];
    88→  return fallback.map(normalizeSingleTrace).filter(Boolean);
    89→}
