     1→const BASE_MARGIN = { l: 32, r: 14, t: 20, b: 36 };
     2→const PIE_MARGIN = { l: 10, r: 10, t: 22, b: 10 };
     3→
     4→function isFiniteNumber(value) {
     5→  return typeof value === 'number' && Number.isFinite(value);
     6→}
     7→
     8→function isDateLike(value) {
     9→  if (value instanceof Date) return Number.isFinite(value.getTime());
    10→  if (typeof value !== 'string') return false;
    11→  return Number.isFinite(Date.parse(value));
    12→}
    13→
    14→function isValidRange(range) {
    15→  if (!Array.isArray(range) || range.length !== 2) return false;
    16→
    17→  const [start, end] = range;
    18→  const bothFinite = isFiniteNumber(start) && isFiniteNumber(end);
    19→  if (bothFinite) return start !== end;
    20→
    21→  const bothDate = isDateLike(start) && isDateLike(end);
    22→  if (bothDate) return Date.parse(start) !== Date.parse(end);
    23→
    24→  return false;
    25→}
    26→
    27→function isValidDomain(domain) {
    28→  if (!Array.isArray(domain) || domain.length !== 2) return false;
    29→  const [start, end] = domain;
    30→  return isFiniteNumber(start) && isFiniteNumber(end) && start >= 0 && end <= 1 && start < end;
    31→}
    32→
    33→function sanitizeAxis(axis, { defaultTickSize = 9 } = {}) {
    34→  const source = axis && typeof axis === 'object' ? { ...axis } : {};
    35→
    36→  if (!isValidRange(source.range)) {
    37→    delete source.range;
    38→  }
    39→
    40→  if (!isValidDomain(source.domain)) {
    41→    delete source.domain;
    42→  }
    43→
    44→  const tickfont = source.tickfont && typeof source.tickfont === 'object' ? source.tickfont : {};
    45→
    46→  return {
    47→    ...source,
    48→    automargin: true,
    49→    tickfont: {
    50→      size: defaultTickSize,
    51→      color: '#6B7280',
    52→      ...tickfont,
    53→    },
    54→  };
    55→}
    56→
    57→function sanitizeMargin(margin, fallbackMargin) {
    58→  if (!margin || typeof margin !== 'object') return fallbackMargin;
    59→
    60→  return {
    61→    l: isFiniteNumber(margin.l) ? margin.l : fallbackMargin.l,
    62→    r: isFiniteNumber(margin.r) ? margin.r : fallbackMargin.r,
    63→    t: isFiniteNumber(margin.t) ? margin.t : fallbackMargin.t,
    64→    b: isFiniteNumber(margin.b) ? margin.b : fallbackMargin.b,
    65→  };
    66→}
    67→
    68→export function normalizeLayout(layout, { hasPie = false, clearTitle = false } = {}) {
    69→  const source = layout && typeof layout === 'object' ? { ...layout } : {};
    70→
    71→  delete source.width;
    72→  delete source.height;
    73→  delete source.responsive;
    74→  delete source.autosize;
    75→
    76→  if (clearTitle) {
    77→    delete source.title;
    78→  }
    79→
    80→  const xaxis = sanitizeAxis(source.xaxis, { defaultTickSize: 9 });
    81→  const yaxis = sanitizeAxis(source.yaxis, { defaultTickSize: 9 });
    82→
    83→  const base = {
    84→    autosize: true,
    85→    paper_bgcolor: 'rgba(0,0,0,0)',
    86→    plot_bgcolor: 'rgba(0,0,0,0)',
    87→    font: {
    88→      family: 'IBM Plex Sans KR, Inter, sans-serif',
    89→      size: 10,
    90→      color: '#1F2937',
    91→    },
    92→    showlegend: hasPie,
    93→    legend: hasPie
    94→      ? { orientation: 'h', y: -0.12, x: 0.5, xanchor: 'center' }
    95→      : { orientation: 'h', y: -0.2, x: 0.5, xanchor: 'center' },
    96→  };
    97→
    98→  const normalized = {
    99→    ...base,
   100→    ...source,
   101→    margin: sanitizeMargin(source.margin, hasPie ? PIE_MARGIN : BASE_MARGIN),
   102→  };
   103→
   104→  if (hasPie) {
   105→    delete normalized.xaxis;
   106→    delete normalized.yaxis;
   107→  } else {
   108→    normalized.xaxis = {
   109→      showgrid: false,
   110→      zeroline: false,
   111→      tickangle: -20,
   112→      ...xaxis,
   113→    };
   114→
   115→    normalized.yaxis = {
   116→      showgrid: true,
   117→      gridcolor: 'rgba(107,114,128,0.16)',
   118→      zeroline: false,
   119→      ...yaxis,
   120→    };
   121→  }
   122→
   123→  if (clearTitle) {
   124→    normalized.title = undefined;
   125→  }
   126→
   127→  return normalized;
   128→}
