     1→import React, { useEffect, useMemo, useRef, useState } from 'react';
     2→
     3→const Plot = React.lazy(() =>
     4→  Promise.all([
     5→    import('react-plotly.js/factory'),
     6→    import('plotly.js-basic-dist-min'),
     7→  ]).then(([{ default: createPlotlyComponent }, Plotly]) => ({
     8→    default: createPlotlyComponent(Plotly.default || Plotly),
     9→  }))
    10→);
    11→
    12→function clamp(value, min, max) {
    13→  return Math.min(max, Math.max(min, value));
    14→}
    15→
    16→class PlotErrorBoundary extends React.Component {
    17→  constructor(props) {
    18→    super(props);
    19→    this.state = { hasError: false };
    20→  }
    21→
    22→  static getDerivedStateFromError() {
    23→    return { hasError: true };
    24→  }
    25→
    26→  render() {
    27→    if (this.state.hasError) {
    28→      return (
    29→        <div
    30→          className="flex items-center justify-center text-sm text-text-secondary"
    31→          style={{ height: this.props.height }}
    32→        >
    33→          {this.props.emptyText}
    34→        </div>
    35→      );
    36→    }
    37→
    38→    return this.props.children;
    39→  }
    40→}
    41→
    42→export default function ResponsivePlotly({
    43→  data,
    44→  layout,
    45→  config,
    46→  mode = 'ratio',
    47→  ratio = 1.16,
    48→  minHeight = 220,
    49→  maxHeight = 460,
    50→  fixedHeight = 280,
    51→  className = '',
    52→  loadingText = '차트 로딩 중...',
    53→  emptyText = '차트 데이터가 없습니다',
    54→}) {
    55→  const containerRef = useRef(null);
    56→  const [containerWidth, setContainerWidth] = useState(0);
    57→
    58→  useEffect(() => {
    59→    const element = containerRef.current;
    60→    if (!element) return undefined;
    61→
    62→    const updateSize = () => {
    63→      setContainerWidth(element.clientWidth || 0);
    64→    };
    65→
    66→    updateSize();
    67→
    68→    if (typeof ResizeObserver === 'undefined') {
    69→      window.addEventListener('resize', updateSize);
    70→      return () => window.removeEventListener('resize', updateSize);
    71→    }
    72→
    73→    const observer = new ResizeObserver((entries) => {
    74→      const nextWidth = entries?.[0]?.contentRect?.width || element.clientWidth || 0;
    75→      setContainerWidth(nextWidth);
    76→    });
    77→
    78→    observer.observe(element);
    79→
    80→    return () => observer.disconnect();
    81→  }, []);
    82→
    83→  const resolvedHeight = useMemo(() => {
    84→    if (mode === 'fixed') {
    85→      return Math.max(120, Math.round(fixedHeight));
    86→    }
    87→
    88→    const nextHeight = Math.round((containerWidth || minHeight) * ratio);
    89→    return clamp(nextHeight, minHeight, maxHeight);
    90→  }, [containerWidth, fixedHeight, maxHeight, minHeight, mode, ratio]);
    91→
    92→  const hasData = Array.isArray(data) && data.length > 0;
    93→
    94→  const revision = useMemo(
    95→    () => `${mode}-${Math.round(containerWidth)}-${resolvedHeight}-${hasData ? data.length : 0}`,
    96→    [containerWidth, data?.length, hasData, mode, resolvedHeight],
    97→  );
    98→
    99→  const mergedLayout = {
   100→    ...(layout || {}),
   101→    autosize: true,
   102→  };
   103→
   104→  const mergedConfig = {
   105→    displayModeBar: false,
   106→    responsive: true,
   107→    ...(config || {}),
   108→  };
   109→
   110→  return (
   111→    <div ref={containerRef} className={`w-full ${className}`}>
   112→      <PlotErrorBoundary height={resolvedHeight} emptyText={emptyText}>
   113→        <React.Suspense
   114→          fallback={(
   115→            <div className="flex items-center justify-center text-sm text-text-secondary" style={{ height: resolvedHeight }}>
   116→              {loadingText}
   117→            </div>
   118→          )}
   119→        >
   120→          <div className="w-full" style={{ height: resolvedHeight }}>
   121→            {hasData ? (
   122→              <Plot
   123→                data={data}
   124→                layout={mergedLayout}
   125→                config={mergedConfig}
   126→                useResizeHandler
   127→                style={{ width: '100%', height: '100%' }}
   128→                revision={revision}
   129→              />
   130→            ) : (
   131→              <div className="flex h-full items-center justify-center text-sm text-text-secondary">
   132→                {emptyText}
   133→              </div>
   134→            )}
   135→          </div>
   136→        </React.Suspense>
   137→      </PlotErrorBoundary>
   138→    </div>
   139→  );
   140→}
