     2→import { normalizeTraces, toFiniteNumber } from './plotly/normalizeTraces';
     3→
     4→function convertDataPointsToTrace(chart) {
     5→  const type = (chart?.chart_type || '').toLowerCase();
     6→  const points = Array.isArray(chart?.data_points) ? chart.data_points : [];
     7→
     8→  const normalized = points
     9→    .map((point, idx) => ({
    10→      label: point?.label ?? `${idx + 1}`,
    11→      value: toFiniteNumber(point?.value),
    12→      color: point?.color,
    13→    }))
    14→    .filter((point) => point.value !== null);
    15→
    16→  if (!normalized.length) return [];
    17→
    18→  const labels = normalized.map((point) => point.label);
    19→  const values = normalized.map((point) => point.value);
    20→
    21→  if (type.includes('bar')) {
    22→    return [{
    23→      type: 'bar',
    24→      x: labels,
    25→      y: values,
    26→      marker: {
    27→        color: normalized.map((point) => point.color || '#FF6B00'),
    28→        opacity: 0.9,
    29→      },
    30→      hovertemplate: '%{x}: %{y}<extra></extra>',
    31→    }];
    32→  }
    33→
    34→  const lineColor = type.includes('risk') ? '#EF4444' : '#FF6B00';
    35→
    36→  return [{
    37→    type: 'scatter',
    38→    mode: 'lines+markers',
    39→    x: labels,
    40→    y: values,
    41→    line: { color: lineColor, width: 2.5, shape: 'spline' },
    42→    marker: { color: lineColor, size: 5 },
