        "hint": "세로 막대 (bar)",
    },
    "horizontal_rank": {
        "keywords": ["순위", "랭킹", "톱", "top", "상위"],
        "hint": "가로 막대 (bar orientation h)",
    },
    "grouped_compare": {
        "keywords": ["비교", "대비", "차이", "vs", "versus"],
